const t=JSON.parse('{"key":"v-cffee6dc","path":"/posts/%E6%B5%8B%E7%BB%98/%E5%9C%B0%E7%B1%8D%E6%B5%8B%E9%87%8F.html","title":"地籍测量","lang":"en-US","frontmatter":{"description":"地籍测量 地籍测量技术文档 1. 概述 地籍测量是获取和表达土地及其附着物的权属、位置、形状、面积、用途等信息的测量工作。它是土地管理的基础，为土地登记、土地税收、土地利用规划等提供数据支持。 2. 测量内容 地籍测量主要包括以下内容： 权属调查: 确定土地及其附着物的权属人、权属性质、权属来源等信息。 界址测量: 测定土地及其附着物的界址点、界址线，并绘制地籍图。 面积测算: 计算土地及其附着物的面积。 地籍图测绘: 将权属调查和界址测量的结果绘制成地籍图，并标注相关信息。","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/posts/%E6%B5%8B%E7%BB%98/%E5%9C%B0%E7%B1%8D%E6%B5%8B%E9%87%8F.html"}],["meta",{"property":"og:site_name","content":"入川为王"}],["meta",{"property":"og:title","content":"地籍测量"}],["meta",{"property":"og:description","content":"地籍测量 地籍测量技术文档 1. 概述 地籍测量是获取和表达土地及其附着物的权属、位置、形状、面积、用途等信息的测量工作。它是土地管理的基础，为土地登记、土地税收、土地利用规划等提供数据支持。 2. 测量内容 地籍测量主要包括以下内容： 权属调查: 确定土地及其附着物的权属人、权属性质、权属来源等信息。 界址测量: 测定土地及其附着物的界址点、界址线，并绘制地籍图。 面积测算: 计算土地及其附着物的面积。 地籍图测绘: 将权属调查和界址测量的结果绘制成地籍图，并标注相关信息。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"en-US"}],["meta",{"property":"og:updated_time","content":"2025-08-16T04:37:55.000Z"}],["meta",{"property":"article:author","content":"入川为王"}],["meta",{"property":"article:modified_time","content":"2025-08-16T04:37:55.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"地籍测量\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2025-08-16T04:37:55.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"入川为王\\",\\"url\\":\\"https://mister-hope.com\\"}]}"]]},"headers":[{"level":2,"title":"地籍测量技术文档","slug":"地籍测量技术文档","link":"#地籍测量技术文档","children":[]}],"git":{"createdTime":1755319075000,"updatedTime":1755319075000,"contributors":[{"name":"TikTrack Developer","email":"user@example.com","commits":1}]},"readingTime":{"minutes":2.74,"words":822},"filePathRelative":"posts/测绘/地籍测量.md","localizedDate":"August 16, 2025","excerpt":"<h1> 地籍测量</h1>\\n<h2> 地籍测量技术文档</h2>\\n<p><strong>1. 概述</strong></p>\\n<p>地籍测量是获取和表达土地及其附着物的权属、位置、形状、面积、用途等信息的测量工作。它是土地管理的基础，为土地登记、土地税收、土地利用规划等提供数据支持。</p>\\n<p><strong>2. 测量内容</strong></p>\\n<p>地籍测量主要包括以下内容：</p>\\n<ul>\\n<li><strong>权属调查:</strong> 确定土地及其附着物的权属人、权属性质、权属来源等信息。</li>\\n<li><strong>界址测量:</strong> 测定土地及其附着物的界址点、界址线，并绘制地籍图。</li>\\n<li><strong>面积测算:</strong> 计算土地及其附着物的面积。</li>\\n<li><strong>地籍图测绘:</strong> 将权属调查和界址测量的结果绘制成地籍图，并标注相关信息。</li>\\n</ul>","autoDesc":true}');export{t as data};
